25	const roundUpInMHPCOFavor = (amount: number): number =>
26	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
27	
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	
30	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
31	
32	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
33	
34	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
35	  { applies: (item) => item.cursed === true, rate: 0.5 },
36	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: 0.3 },
37	];
38	
39	const surchargesFor = (item: Item): number =>
40	  ITEM_SURCHARGES.reduce(
41	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
42	    0,
43	  );
44	
45	const sumOfBasePrices = (items: Array<Item>): number =>
46	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
47	
48	const sumOfItemSurcharges = (items: Array<Item>): number =>
49	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
50	
51	const COMPONENT_TYPES = ["rune", "moonstone"];
52	const BLOCK_SIZE = 3;
53	
54	const countOfType = (items: Array<Item>, type: string): number =>
55	  items.filter((item) => item.type === type).length;
56	
57	const formsABlock = (items: Array<Item>, type: string): boolean =>
58	  countOfType(items, type) === BLOCK_SIZE;
59	
60	const blockDiscountFor = (items: Array<Item>): number =>
61	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
62	  BLOCK_OF_THREE_DISCOUNT;
63	
64	const basePremiumFor = (items: Array<Item>): number =>
65	  sumOfBasePrices(items) - blockDiscountFor(items);
66	
67	const firstInsuranceSurchargeOf = (amount: number): number =>
68	  amount * FIRST_INSURANCE_SURCHARGE;
69	
70	const loyaltyDiscountOf = (amount: number, customer: Customer): number =>
71	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? amount * LOYALTY_DISCOUNT : 0;
72	
73	const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;
74	
75	const quoteStep = (step: QuoteStep, customer: Customer): { premium: number } => {
76	  const basePremium = basePremiumFor(step.items);
77	  const itemSurchargeTotal = sumOfItemSurcharges(step.items);
78	  const premiumBeforeRounding = withProcessingFee(
79	    basePremium
80	      + firstInsuranceSurchargeOf(basePremium)
81	      - loyaltyDiscountOf(basePremium, customer)
82	      + itemSurchargeTotal,
83	  );
84	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
85	};
